    $this->Event->id = $id;
    if (!$this->Event->exists()) {
        throw new NotFoundException(__('Invalid event'));
    }
    // User has filled in his contact form, send out the email.
    if ($this->request->is('post') || $this->request->is('put')) {
        if (!isset($this->request->data['Event'])) {
