        }
        $message = $this->request->data['Event']['message'];
        if (empty($message)) {
            $error = __('You must specify a message.');
            if ($this->_isRest()) {
                throw new MethodNotAllowedException($error);
            } else {
                $this->Flash->error($error);
                $this->redirect(array('action' => 'contact', $id));
            }
        }

        $creator_only = false;
