		$subelement = '';
	} elseif ($element_type == 'cabinetmed_cons') {
		$classpath = 'cabinetmed/class';
		$module = 'cabinetmed';
		$subelement = 'cabinetmedcons';
	} elseif ($element_type == 'fichinter') {
